import { useEffect, useState, useCallback, useRef } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { ShieldAlert, WifiOff, RefreshCw } from 'lucide-react';
import { queryClient } from '@/lib/queryClient';
import { focusManager } from '@tanstack/react-query';

type ConnectionStatus = 'online' | 'offline' | 'error';

export function HealthMonitor() {
  const [status, setStatus] = useState<ConnectionStatus>('online');
  const [isRetrying, setIsRetrying] = useState(false);
  const [wasOffline, setWasOffline] = useState(false);
  const retryCountRef = useRef(0);
  const retryTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const refetchAll = useCallback(() => {
    console.log('🔄 HealthMonitor: Ensuring React Query is aware of focus...');
    // React Query's focusManager automatically triggers refetch for all queries 
    // that have refetchOnWindowFocus: true (which is our default).
    // We just need to ensure it knows the window is focused.
    focusManager.setFocused(true);
  }, []);

  const validateSession = useCallback(async () => {
    try {
      const { data: { session }, error } = await supabase.auth.getSession();
      if (error || !session) {
        console.warn('⚠️ Session invalid on focus, AuthProvider will handle redirect.');
      }
    } catch (e) {
      console.error('❌ Error validating session on focus:', e);
    }
  }, []);

  const checkConnection = useCallback(async (): Promise<ConnectionStatus> => {
    if (!window.navigator.onLine) {
      return 'offline';
    }
    try {
      const { error } = await supabase.from('schools').select('id').limit(1).maybeSingle();
      if (error && error.code !== 'PGRST116') throw error;
      return 'online';
    } catch (err) {
      console.error('⚠️ DB health check failed:', err);
      return 'error';
    }
  }, []);

  const handleRetry = async () => {
    setIsRetrying(true);
    const newStatus = await checkConnection();
    setStatus(newStatus);
    setIsRetrying(false);
    if (newStatus === 'online') {
      retryCountRef.current = 0;
      refetchAll();
    }
  };

  useEffect(() => {
    checkConnection().then(setStatus);

    const handleFocusOrVisible = async () => {
      if (document.visibilityState === 'visible') {
        // Just check connection, React Query handles the focus refetching automatically
        const newStatus = await checkConnection();
        setStatus(newStatus);

        if (newStatus === 'online') {
          await validateSession();
        }
      }
    };

    window.addEventListener('online', handleFocusOrVisible);
    window.addEventListener('offline', () => setStatus('offline'));
    // We don't need manual focus/visibility listeners for refetching 
    // because React Query handles refetchOnWindowFocus automatically.
    // We only listen to visibilitychange to update our internal connection status and session.
    document.addEventListener('visibilitychange', handleFocusOrVisible);

    // Periodic health check every 60s
    const interval = setInterval(async () => {
      if (window.navigator.onLine) {
        const newStatus = await checkConnection();
        if (newStatus !== status) setStatus(newStatus);
      }
    }, 60000);

    return () => {
      clearInterval(interval);
      if (retryTimerRef.current) clearTimeout(retryTimerRef.current);
      window.removeEventListener('online', handleFocusOrVisible);
      window.removeEventListener('offline', () => setStatus('offline'));
      document.removeEventListener('visibilitychange', handleFocusOrVisible);
    };
  }, [checkConnection, validateSession, status]);

  // Show "reconnected" green banner briefly
  if (wasOffline && status === 'online') {
    return (
      <div className="fixed top-4 left-1/2 -translate-x-1/2 z-[10000] animate-in slide-in-from-top-4 duration-500" dir="rtl">
        <div className="px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 bg-emerald-500 border border-emerald-600 text-white">
          <div className="w-2 h-2 rounded-full bg-white animate-pulse" />
          <span className="text-sm font-black tracking-tight">تم استعادة الاتصال بنجاح</span>
        </div>
      </div>
    );
  }

  if (status === 'online') return null;

  return (
    <div className="fixed top-4 left-1/2 -translate-x-1/2 z-[10000] animate-in slide-in-from-top-4 duration-500" dir="rtl">
      <div className={`px-6 py-3 rounded-full shadow-2xl flex items-center gap-4 border ${
        status === 'offline' ? 'bg-amber-500 border-amber-600' : 'bg-rose-500 border-rose-600'
      } text-white`}>
        {status === 'offline' ? <WifiOff className="w-5 h-5" /> : <ShieldAlert className="w-5 h-5" />}

        <span className="text-sm font-black tracking-tight">
          {status === 'offline' ? 'لا يوجد اتصال بالإنترنت — جاري إعادة المحاولة...' : 'خطأ في الاتصال بقاعدة البيانات'}
        </span>

        <button 
          onClick={handleRetry} 
          disabled={isRetrying}
          className="p-2 rounded-lg bg-white/20 hover:bg-white/30 transition-colors disabled:opacity-50"
          title="إعادة المحاولة"
        >
          <RefreshCw className={`w-4 h-4 ${isRetrying ? 'animate-spin' : ''}`} />
        </button>
      </div>
    </div>
  );
}

import { useEffect } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { useAuth } from '@/contexts/AuthContext';

export default function PwaManager() {
  const { user } = useAuth();

  useEffect(() => {
    const updateManifest = async () => {
      let name = "المدرسة الذكية";
      let shortName = "المدرسة";
      const defaultIcon = "/icons/icon-192.png";
      let icon = defaultIcon;
      let slug = "";
      let themeColor = "#1e293b";

      // 1. Determine school context
      if (user?.schoolId) {
        try {
          const { data, error } = await supabase
            .from('schools')
            .select('name, slug, logo_url')
            .eq('id', user.schoolId)
            .maybeSingle();

          if (error) {
            console.error('Error fetching PWA school data:', error);
          } else if (data) {
            const school = data as any;
            name = school.name;
            shortName = school.name.split(' ')[0];
            icon = school.logo_url || "/icons/icon-192.png";
            slug = school.slug;
            themeColor = "#1e293b";
          }
        } catch (err) {
          console.error('Fatal error in PwaManager fetch:', err);
        }
      } else {
        // Check URL for registration slugs or query params
        const pathParts = window.location.pathname.split('/');
        const isReg = pathParts.includes('register');
        const urlSlug = pathParts[pathParts.length - 1];
        const params = new URLSearchParams(window.location.search);
        const querySlug = params.get('school');

        const finalSlug = querySlug || (isReg ? urlSlug : null);

        if (finalSlug) {
           try {
             const { data, error } = await supabase
              .from('schools')
              .select('name, slug, logo_url')
              .eq('slug', finalSlug)
              .maybeSingle();

            if (error) {
              console.error('Error fetching PWA school data by slug:', error);
            } else if (data) {
              const school = data as any;
              name = school.name;
              shortName = school.name.split(' ')[0];
              icon = school.logo_url || "/icons/icon-192.png";
              slug = school.slug;
              themeColor = "#1e293b";
            }
          } catch (err) {
            console.error('Fatal error in PwaManager fetch by slug:', err);
          }
        }
      }

      // Add cache busting to icon to force refresh when changed in dashboard
      const timestamp = Date.now();
      const cacheBustIcon = icon.includes('?') ? `${icon}&v=${timestamp}` : `${icon}?v=${timestamp}`;

      // @ts-ignore - Deep type instantiation
      const manifest = {
        name: name,
        short_name: shortName,
        description: `نظام إدارة ${name} الذكي`,
        start_url: window.location.origin + (slug ? `/?school=${slug}` : "/"),
        display: "standalone",
        background_color: "#0a0f1e",
        theme_color: themeColor,
        icons: [
          {
            src: cacheBustIcon.startsWith('http') ? cacheBustIcon : window.location.origin + (cacheBustIcon.startsWith('/') ? cacheBustIcon : '/' + cacheBustIcon),
            sizes: "192x192",
            type: "image/png",
            purpose: "any maskable"
          },
          {
            src: cacheBustIcon.startsWith('http') ? cacheBustIcon : window.location.origin + (cacheBustIcon.startsWith('/') ? cacheBustIcon : '/' + cacheBustIcon),
            sizes: "512x512",
            type: "image/png"
          }
        ]
      };

      const stringManifest = JSON.stringify(manifest);
      const blob = new Blob([stringManifest], { type: 'application/json' });
      const manifestURL = URL.createObjectURL(blob);

      // 3. Update DOM
      const link = document.querySelector('link[rel="manifest"]') as HTMLLinkElement;
      if (link) {
        link.href = manifestURL;
      }

      // 4. Update Title & Favicon & Theme Color
      document.title = name;

      const updateIcon = (rel: string, href: string) => {
        let link = document.querySelector(`link[rel="${rel}"]`) as HTMLLinkElement;
        if (!link) {
          link = document.createElement('link');
          link.rel = rel;
          document.head.appendChild(link);
        }
        link.href = href;
      };

      const finalIcon = cacheBustIcon.startsWith('http') 
        ? cacheBustIcon 
        : window.location.origin + (cacheBustIcon.startsWith('/') ? cacheBustIcon : '/' + cacheBustIcon);

      updateIcon('icon', finalIcon);
      updateIcon('apple-touch-icon', finalIcon);
      updateIcon('shortcut icon', finalIcon);

      let metaTheme = document.querySelector("meta[name='theme-color']") as HTMLMetaElement;
      if (!metaTheme) {
        metaTheme = document.createElement('meta');
        metaTheme.name = 'theme-color';
        document.head.appendChild(metaTheme);
      }
      metaTheme.content = themeColor;
    };

    updateManifest();

    // 2. Real-time update listener for school branding
    const channel = supabase
      .channel('pwa-branding-updates')
      .on(
        'postgres_changes',
        {
          event: 'UPDATE',
          schema: 'public',
          table: 'schools',
          filter: user?.schoolId ? `id=eq.${user.schoolId}` : undefined
        },
        () => {
          // Re-run the manifest update when school data changes
          updateManifest();
        }
      )
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user?.schoolId, user?.id]);

  return null;
}

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const badgeVariants = cva(
  "inline-flex items-center rounded-full border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default: "border-transparent bg-primary text-primary-foreground hover:bg-primary/80",
        secondary: "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive: "border-transparent bg-destructive text-destructive-foreground hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps extends React.HTMLAttributes<HTMLDivElement>, VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return <div className={cn(badgeVariants({ variant }), className)} {...props} />;
}

export { Badge, badgeVariants };

import * as React from "react";
import { Slot } from "@radix-ui/react-slot";
import { cva, type VariantProps } from "class-variance-authority";

import { cn } from "@/lib/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-xl text-sm font-bold ring-offset-background transition-all duration-200 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0 active:scale-[0.98]",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground hover:bg-primary/90 shadow-sm hover:shadow-md",
        destructive: "bg-destructive text-destructive-foreground hover:bg-destructive/90 shadow-sm",
        outline: "border border-input bg-background hover:bg-accent hover:text-accent-foreground shadow-sm",
        secondary: "bg-secondary text-secondary-foreground hover:bg-secondary/80 shadow-sm",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline font-bold",
      },
      size: {
        default: "h-10 px-4 py-2",
        sm: "h-8 px-3 text-xs",
        lg: "h-12 px-8 text-base",
        icon: "h-10 w-10",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button";
    return <Comp className={cn(buttonVariants({ variant, size, className }))} ref={ref} {...props} />;
  },
);
Button.displayName = "Button";

export { Button, buttonVariants };

import * as React from "react";
import * as LabelPrimitive from "@radix-ui/react-label";
import { Slot } from "@radix-ui/react-slot";
import { Controller, ControllerProps, FieldPath, FieldValues, FormProvider, useFormContext } from "react-hook-form";

import { cn } from "@/lib/utils";
import { Label } from "@/components/ui/label";

const Form = FormProvider;

type FormFieldContextValue<
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
> = {
  name: TName;
};

const FormFieldContext = React.createContext<FormFieldContextValue>({} as FormFieldContextValue);

const FormField = <
  TFieldValues extends FieldValues = FieldValues,
  TName extends FieldPath<TFieldValues> = FieldPath<TFieldValues>,
>({
  ...props
}: ControllerProps<TFieldValues, TName>) => {
  return (
    <FormFieldContext.Provider value={{ name: props.name }}>
      <Controller {...props} />
    </FormFieldContext.Provider>
  );
};

const useFormField = () => {
  const fieldContext = React.useContext(FormFieldContext);
  const itemContext = React.useContext(FormItemContext);
  const { getFieldState, formState } = useFormContext();

  const fieldState = getFieldState(fieldContext.name, formState);

  if (!fieldContext) {
    throw new Error("useFormField should be used within <FormField>");
  }

  const { id } = itemContext;

  return {
    id,
    name: fieldContext.name,
    formItemId: `${id}-form-item`,
    formDescriptionId: `${id}-form-item-description`,
    formMessageId: `${id}-form-item-message`,
    ...fieldState,
  };
};

type FormItemContextValue = {
  id: string;
};

const FormItemContext = React.createContext<FormItemContextValue>({} as FormItemContextValue);

const FormItem = React.forwardRef<HTMLDivElement, React.HTMLAttributes<HTMLDivElement>>(
  ({ className, ...props }, ref) => {
    const id = React.useId();

    return (
      <FormItemContext.Provider value={{ id }}>
        <div ref={ref} className={cn("space-y-2", className)} {...props} />
      </FormItemContext.Provider>
    );
  },
);
FormItem.displayName = "FormItem";

const FormLabel = React.forwardRef<
  React.ElementRef<typeof LabelPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof LabelPrimitive.Root>
>(({ className, ...props }, ref) => {
  const { error, formItemId } = useFormField();

  return <Label ref={ref} className={cn(error && "text-destructive", className)} htmlFor={formItemId} {...props} />;
});
FormLabel.displayName = "FormLabel";

const FormControl = React.forwardRef<React.ElementRef<typeof Slot>, React.ComponentPropsWithoutRef<typeof Slot>>(
  ({ ...props }, ref) => {
    const { error, formItemId, formDescriptionId, formMessageId } = useFormField();

    return (
      <Slot
        ref={ref}
        id={formItemId}
        aria-describedby={!error ? `${formDescriptionId}` : `${formDescriptionId} ${formMessageId}`}
        aria-invalid={!!error}
        {...props}
      />
    );
  },
);
FormControl.displayName = "FormControl";

const FormDescription = React.forwardRef<HTMLParagraphElement, React.HTMLAttributes<HTMLParagraphElement>>(
  ({ className, ...props }, ref) => {
    const { formDescriptionId } = useFormField();

    return <p ref={ref} id={formDescriptionId} className={cn("text-sm text-muted-foreground", className)} {...props} />;
  },
);
FormDescription.displayName = "FormDescription";

const FormMessage = React.forwardRef<HTMLParagraphElement, React.HTMLAttributes<HTMLParagraphElement>>(
  ({ className, children, ...props }, ref) => {
    const { error, formMessageId } = useFormField();
    const body = error ? String(error?.message) : children;

    if (!body) {
      return null;
    }

    return (
      <p ref={ref} id={formMessageId} className={cn("text-sm font-medium text-destructive", className)} {...props}>
        {body}
      </p>
    );
  },
);
FormMessage.displayName = "FormMessage";

export { useFormField, Form, FormItem, FormLabel, FormControl, FormDescription, FormMessage, FormField };

